                    // effects, don't reorder it past the assignment target. The assignment
                    // target is being read so it may be changed by the side effect. For
                    // example, "fn()" may change "foo" here:
                    // ```js
                    // let a = fn();
                    // foo += a;
                    // ```
                    return Some(false);
