                                elem.to_expression_mut(),
                                search_for,
                                replacement,
                                replacement_has_side_effect,
                                ctx,
                            ) {
                                return Some(changed);
                            }
                        }
                    }
                }
            }
            Expression::ObjectExpression(obj_expr) => {
                for prop in &mut obj_expr.properties {
                    match prop {
                        ObjectPropertyKind::ObjectProperty(prop) => {
